SELECT message
FROM test_notifications
WHERE notification_date = '2023-10-02';

SELECT approval_id
FROM test_approvals
WHERE approval_status = 'approved';

SELECT SUM(doc_size) AS total_size
FROM test_documents
WHERE doc_size > 400000;

SELECT doc_name
FROM test_documents
WHERE doc_type = 'log';

SELECT AVG(adc_uv) AS final_avg_adc_uv
FROM test_results
WHERE test_status = 'passed' AND test_duration > 30;
